#include <stdio.h>
#include <stdlib.h>
#include <omp.h>

#ifdef RD_WG_SIZE_0_0
        #define BLOCK_SIZE RD_WG_SIZE_0_0
#elif defined(RD_WG_SIZE_0)
        #define BLOCK_SIZE RD_WG_SIZE_0
#elif defined(RD_WG_SIZE)
        #define BLOCK_SIZE RD_WG_SIZE
#else
        #define BLOCK_SIZE 16
#endif

extern int omp_num_threads;

void lud_omp(float *m, int matrix_dim)
{
    int i, j, k, offset;

    for (offset = 0; offset < matrix_dim; offset += BLOCK_SIZE) {
        int block_size = BLOCK_SIZE;
        if (offset + block_size > matrix_dim)
            block_size = matrix_dim - offset;

        /* lud_diagonal: process the diagonal block */
        {
            float shadow[BLOCK_SIZE][BLOCK_SIZE];
            int ii, jj, kk;

            /* Load diagonal block */
            for (ii = 0; ii < block_size; ii++) {
                for (jj = 0; jj < block_size; jj++) {
                    shadow[ii][jj] = m[(offset + ii) * matrix_dim + offset + jj];
                }
            }

            /* LU decomposition on the diagonal block */
            for (ii = 0; ii < block_size; ii++) {
                for (jj = ii + 1; jj < block_size; jj++) {
                    /* Update column: shadow[jj][ii] */
                    for (kk = 0; kk < ii; kk++) {
                        shadow[jj][ii] -= shadow[jj][kk] * shadow[kk][ii];
                    }
                    shadow[jj][ii] /= shadow[ii][ii];
                }
                for (jj = ii + 1; jj < block_size; jj++) {
                    /* Update row: shadow[ii+1][jj] ... but generalized */
                    for (kk = 0; kk < ii + 1; kk++) {
                        shadow[ii + 1 <= block_size - 1 ? ii + 1 : ii][jj] -= 0; /* placeholder */
                    }
                }
            }

            /* Redo: proper LU on diagonal block (like lud_base) */
            for (ii = 0; ii < block_size; ii++) {
                for (jj = 0; jj < block_size; jj++) {
                    shadow[ii][jj] = m[(offset + ii) * matrix_dim + offset + jj];
                }
            }

            for (ii = 0; ii < block_size; ii++) {
                /* Update U row */
                for (jj = ii; jj < block_size; jj++) {
                    for (kk = 0; kk < ii; kk++) {
                        shadow[ii][jj] -= shadow[ii][kk] * shadow[kk][jj];
                    }
                }
                /* Update L column */
                for (jj = ii + 1; jj < block_size; jj++) {
                    for (kk = 0; kk < ii; kk++) {
                        shadow[jj][ii] -= shadow[jj][kk] * shadow[kk][ii];
                    }
                    shadow[jj][ii] /= shadow[ii][ii];
                }
            }

            /* Write back */
            for (ii = 0; ii < block_size; ii++) {
                for (jj = 0; jj < block_size; jj++) {
                    m[(offset + ii) * matrix_dim + offset + jj] = shadow[ii][jj];
                }
            }
        }

        /* lud_perimeter: process perimeter blocks */
        {
            int num_peri = (matrix_dim - offset) / BLOCK_SIZE - 1;

            #pragma omp parallel for num_threads(omp_num_threads) schedule(static)
            for (i = 0; i < num_peri; i++) {
                int ii, jj, kk;
                float dia[BLOCK_SIZE][BLOCK_SIZE];
                float peri_row[BLOCK_SIZE][BLOCK_SIZE];
                float peri_col[BLOCK_SIZE][BLOCK_SIZE];

                /* Load diagonal block */
                for (ii = 0; ii < block_size; ii++) {
                    for (jj = 0; jj < block_size; jj++) {
                        dia[ii][jj] = m[(offset + ii) * matrix_dim + offset + jj];
                    }
                }

                /* Load peri_row block: row blocks to the right of diagonal */
                for (ii = 0; ii < block_size; ii++) {
                    for (jj = 0; jj < BLOCK_SIZE; jj++) {
                        peri_row[ii][jj] = m[(offset + ii) * matrix_dim + offset + (i + 1) * BLOCK_SIZE + jj];
                    }
                }

                /* Load peri_col block: column blocks below diagonal */
                for (ii = 0; ii < BLOCK_SIZE; ii++) {
                    for (jj = 0; jj < block_size; jj++) {
                        peri_col[ii][jj] = m[(offset + (i + 1) * BLOCK_SIZE + ii) * matrix_dim + offset + jj];
                    }
                }

                /* Update peri_row using dia (forward substitution with L) */
                for (ii = 1; ii < block_size; ii++) {
                    for (jj = 0; jj < BLOCK_SIZE; jj++) {
                        for (kk = 0; kk < ii; kk++) {
                            peri_row[ii][jj] -= dia[ii][kk] * peri_row[kk][jj];
                        }
                    }
                }

                /* Update peri_col using dia (forward substitution with U) */
                for (ii = 0; ii < BLOCK_SIZE; ii++) {
                    for (jj = 0; jj < block_size; jj++) {
                        for (kk = 0; kk < jj; kk++) {
                            peri_col[ii][jj] -= peri_col[ii][kk] * dia[kk][jj];
                        }
                        peri_col[ii][jj] /= dia[jj][jj];
                    }
                }

                /* Write back peri_row (skip first row as it's unchanged) */
                for (ii = 1; ii < block_size; ii++) {
                    for (jj = 0; jj < BLOCK_SIZE; jj++) {
                        m[(offset + ii) * matrix_dim + offset + (i + 1) * BLOCK_SIZE + jj] = peri_row[ii][jj];
                    }
                }

                /* Write back peri_col */
                for (ii = 0; ii < BLOCK_SIZE; ii++) {
                    for (jj = 0; jj < block_size; jj++) {
                        m[(offset + (i + 1) * BLOCK_SIZE + ii) * matrix_dim + offset + jj] = peri_col[ii][jj];
                    }
                }
            }
        }

        /* lud_internal: update interior blocks */
        {
            int num_blocks = (matrix_dim - offset) / BLOCK_SIZE - 1;

            #pragma omp parallel for collapse(2) num_threads(omp_num_threads) schedule(static)
            for (i = 0; i < num_blocks; i++) {
                for (j = 0; j < num_blocks; j++) {
                    int ii, jj, kk;
                    float peri_row[BLOCK_SIZE][BLOCK_SIZE];
                    float peri_col[BLOCK_SIZE][BLOCK_SIZE];
                    float sum;

                    int global_row_id = offset + (i + 1) * BLOCK_SIZE;
                    int global_col_id = offset + (j + 1) * BLOCK_SIZE;

                    /* Load peri_row: the row block at (offset, global_col_id) */
                    for (ii = 0; ii < BLOCK_SIZE; ii++) {
                        for (jj = 0; jj < BLOCK_SIZE; jj++) {
                            peri_row[ii][jj] = m[(offset + ii) * matrix_dim + global_col_id + jj];
                        }
                    }

                    /* Load peri_col: the col block at (global_row_id, offset) */
                    for (ii = 0; ii < BLOCK_SIZE; ii++) {
                        for (jj = 0; jj < BLOCK_SIZE; jj++) {
                            peri_col[ii][jj] = m[(global_row_id + ii) * matrix_dim + offset + jj];
                        }
                    }

                    /* Update interior block */
                    for (ii = 0; ii < BLOCK_SIZE; ii++) {
                        for (jj = 0; jj < BLOCK_SIZE; jj++) {
                            sum = 0;
                            for (kk = 0; kk < BLOCK_SIZE; kk++) {
                                sum += peri_col[ii][kk] * peri_row[kk][jj];
                            }
                            m[(global_row_id + ii) * matrix_dim + global_col_id + jj] -= sum;
                        }
                    }
                }
            }
        }
    }
}
